foreach ($u in $uploads) {
  $path = Join-Path $dir $u.file
  $bytes = [System.IO.File]::ReadAllBytes($path)
  try {
    Invoke-RestMethod -Uri $u.url -Method Put -ContentType "image/jpeg" -Body $bytes -TimeoutSec 120
    Write-Output "ok $($u.file)"
  } catch {
    Write-Output "err $($u.file): $($_.Exception.Message)"
  }
}
